package com.talent.platform.security;
import com.talent.platform.common.*;import org.springframework.jdbc.core.JdbcTemplate;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequestMapping("/api/v1/audit-logs") public class AuditController {private final JdbcTemplate db;private final PermissionService permissions;public AuditController(JdbcTemplate db,PermissionService permissions){this.db=db;this.permissions=permissions;}@GetMapping public ApiResponse<List<Map<String,Object>>> list(@RequestParam(defaultValue="100")int limit){permissions.require(Permissions.AUDIT_READ);return ApiResponse.ok(db.queryForList("select l.id,l.action,l.target_type,l.target_id,l.request_id,l.before_value,l.after_value,l.created_at,u.display_name operator_name from operation_log l left join sys_user u on u.id=l.user_id order by l.id desc limit ?",Math.min(Math.max(limit,1),500)));}}
